import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api/axiosConfig';
import ReactMarkdown from 'react-markdown';
import { FileText, ChevronLeft, ShieldCheck, PieChart, Activity } from 'lucide-react';
import toast from 'react-hot-toast';

const PortfolioPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    const fetchStrategy = async () => {
      try {
        const res = await api.get(`/portfolio/${id}`);
        // Ensure holdings is an array/object if it was returned as a string
        const formattedData = {
          ...res.data,
          holdings: typeof res.data.holdings === 'string' ? JSON.parse(res.data.holdings) : res.data.holdings
        };
        setData(formattedData);
      } catch (err) {
        toast.error("VAULT_ACCESS_DENIED: Invalid Strategy ID");
        navigate('/dashboard');
      }
    };
    fetchStrategy();
  }, [id, navigate]);

  const handleExportPDF = async () => {
    setIsExporting(true);
    const toastId = toast.loading("GENERATING_INSTITUTIONAL_REPORT...");
    try {
      // Calling the MarketServices.export_pdf_report endpoint on your backend
      const response = await api.post('/portfolio/export', data, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `FINIFY_AUDIT_${id}.pdf`);
      document.body.appendChild(link);
      link.click();
      toast.success("REPORT_EXPORTED_SUCCESSFULLY", { id: toastId });
    } catch (err) {
      toast.error("EXPORT_FAILED: Template Engine Offline", { id: toastId });
    } finally {
      setIsExporting(false);
    }
  };

  if (!data) return (
    <div className="min-h-screen bg-[#121212] flex flex-col items-center justify-center font-mono">
      <div className="w-12 h-1 bg-emerald-500/20 rounded-full overflow-hidden">
        <div className="h-full bg-emerald-500 animate-[loading_2s_infinite]" style={{ width: '40%' }} />
      </div>
      <p className="mt-4 text-[10px] text-emerald-500 uppercase tracking-[0.5em]">decrypting_vault_node...</p>
    </div>
  );

  return (
    <div className="max-w-6xl mx-auto pb-20 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* 🧭 Navigation & Actions */}
      <div className="flex justify-between items-center mb-10 border-b border-white/5 pb-6">
        <button 
          onClick={() => navigate('/dashboard')}
          className="flex items-center gap-2 text-[10px] text-white/40 hover:text-emerald-500 transition-colors uppercase font-bold tracking-widest"
        >
          <ChevronLeft size={14} /> Back_to_Vault
        </button>
        
        <button 
          onClick={handleExportPDF}
          disabled={isExporting}
          className="flex items-center gap-2 bg-emerald-500 text-black px-5 py-2 rounded-lg text-[10px] font-bold uppercase tracking-widest hover:bg-emerald-400 disabled:opacity-50 transition-all shadow-[0_0_15px_rgba(16,185,129,0.1)]"
        >
          <FileText size={14} /> {isExporting ? 'Generating...' : 'Export_Strategy_PDF'}
        </button>
      </div>

      {/* 🏛️ Strategy Identity Header */}
      <div className="mb-12">
        <div className="flex items-center gap-3 mb-2">
          <div className="px-2 py-0.5 rounded bg-emerald-500/10 border border-emerald-500/20 text-emerald-500 text-[9px] font-bold uppercase">
            Strategy_Audit_Confirmed
          </div>
          <span className="text-white/20 text-[9px] font-mono">NODE_HASH: {id.toString(16).padStart(8, '0')}</span>
        </div>
        <h1 className="text-3xl font-bold tracking-tighter text-white uppercase">{data.goal}</h1>
        <p className="text-[10px] text-white/30 uppercase tracking-[0.2em] mt-2">
          Generated: {new Date(data.created_at).toLocaleString()} // Status: Immutable_Record
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Summary & Rationale */}
        <div className="lg:col-span-2 space-y-8">
          <section className="p-8 bg-[#1a1a1a] border border-white/10 rounded-2xl relative overflow-hidden group">
            <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500/30 group-hover:bg-emerald-500 transition-colors" />
            <h2 className="flex items-center gap-2 text-[10px] font-bold text-emerald-500 uppercase tracking-widest mb-6">
              <Activity size={14} /> 01_Agentic_Synthesis_Summary
            </h2>
            <p className="text-white/80 leading-relaxed font-sans">{data.summary}</p>
          </section>

          <section className="p-8 bg-[#1a1a1a] border border-white/10 rounded-2xl">
            <h2 className="flex items-center gap-2 text-[10px] font-bold text-emerald-500 uppercase tracking-widest mb-6">
              <ShieldCheck size={14} /> 02_Strategic_Audit_Rationale
            </h2>
            <article className="prose prose-invert prose-emerald prose-sm max-w-none">
              <ReactMarkdown>{data.rationale}</ReactMarkdown>
            </article>
          </section>
        </div>

        {/* Right Column: Holdings & Risk */}
        <div className="space-y-8">
          <section className="p-8 bg-[#1a1a1a] border border-white/10 rounded-2xl">
            <h2 className="flex items-center gap-2 text-[10px] font-bold text-emerald-500 uppercase tracking-widest mb-6">
              <PieChart size={14} /> 03_Asset_Allocation
            </h2>
            <article className="prose prose-invert prose-emerald prose-sm max-w-none">
              <ReactMarkdown>{typeof data.holdings === 'string' ? data.holdings : JSON.stringify(data.holdings)}</ReactMarkdown>
            </article>
          </section>

          {/* Risk Score Widget */}
          <section className="p-8 bg-emerald-500/5 border border-emerald-500/10 rounded-2xl">
            <h3 className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest mb-4 text-center">Protocol_Risk_Rating</h3>
            <div className="flex flex-col items-center">
              <div className="text-4xl font-mono font-bold text-white mb-2">{data.risk_score || '0'}<span className="text-emerald-500/30 text-xl">/10</span></div>
              <div className="w-full h-1.5 bg-white/5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-emerald-500 shadow-[0_0_10px_#10b981]" 
                  style={{ width: `${(data.risk_score || 0) * 10}%` }} 
                />
              </div>
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default PortfolioPage;
